pub const IndexedAttestation = struct {
    attesting_indices_bytes: []const u8,
    data: AttestationData,
    signature: Bytes96,

    const Self = @This();

    pub fn sszBytesLen(self: *const Self) usize {
        var size: usize = 228;
        size += self.attesting_indices_bytes.len;
        return size;
    }

    pub fn sszAppend(self: *const Self, writer: anytype) !void {
        // Static section
        var offset: u32 = 228;
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.attesting_indices_bytes.len);
        try self.data.sszAppend(writer);
        try self.signature.sszAppend(writer);

        // Dynamic section
        try writer.writeAll(self.attesting_indices_bytes);
    }

    pub fn toSszBytes(self: *const Self, allocator: std.mem.Allocator) ![]u8 {
        var buf = std.ArrayList(u8).init(allocator);
        errdefer buf.deinit();
        try self.sszAppend(buf.writer());
        return buf.toOwnedSlice();
    }

    pub fn fromSszBytes(bytes: []const u8) !Self {
        if (bytes.len < 228) return error.BufferTooSmall;
        const offset0 = std.mem.readInt(u32, bytes[0..4][0..4], .little);
        if (offset0 != 228) return error.InvalidOffset;
        var result: Self = undefined;
        result.data = try AttestationData.fromSszBytes(bytes[4..132]);
        result.signature = try Bytes96.fromSszBytes(bytes[132..228]);
        result.attesting_indices_bytes = bytes[offset0..bytes.len];
        return result;
    }

    pub fn treeHashRoot(self: *const Self) [32]u8 {
        var h = Hasher.init();
        self.treeHashWith(&h);
        return h.finish();
    }

    pub fn treeHashWith(self: *const Self, h: *Hasher) void {
        const idx = h.index();
        {
            const sub_idx = h.index();
            const num_indices = self.attesting_indices_bytes.len / 8;
            var i: usize = 0;
            while (i < num_indices) : (i += 1) {
                const v = std.mem.readInt(u64, self.attesting_indices_bytes[i * 8 ..][0..8], .little);
                h.appendUint64(v);
            }
            h.fillUpTo32();
            h.merkleizeWithMixin(sub_idx, num_indices, 512);
        }
        self.data.treeHashWith(h);
        self.signature.treeHashWith(h);
        h.merkleize(idx);
    }
};


