pub const ExecutionPayload = struct {
    parent_hash: Bytes32,
    fee_recipient: Bytes20,
    state_root: Bytes32,
    receipts_root: Bytes32,
    logs_bloom: Bytes256,
    prev_randao: Bytes32,
    block_number: u64,
    gas_limit: u64,
    gas_used: u64,
    timestamp: u64,
    extra_data: []const u8,
    base_fee_per_gas: Bytes32,
    block_hash: Bytes32,
    transactions_bytes: []const u8,
    withdrawals_bytes: []const u8,
    blob_gas_used: u64,
    excess_blob_gas: u64,

    const Self = @This();

    pub fn sszBytesLen(self: *const Self) usize {
        var size: usize = 528;
        size += self.extra_data.len;
        size += self.transactions_bytes.len;
        size += self.withdrawals_bytes.len;
        return size;
    }

    pub fn sszAppend(self: *const Self, writer: anytype) !void {
        // Static section
        var offset: u32 = 528;
        try self.parent_hash.sszAppend(writer);
        try self.fee_recipient.sszAppend(writer);
        try self.state_root.sszAppend(writer);
        try self.receipts_root.sszAppend(writer);
        try self.logs_bloom.sszAppend(writer);
        try self.prev_randao.sszAppend(writer);
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u64, self.block_number)));
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u64, self.gas_limit)));
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u64, self.gas_used)));
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u64, self.timestamp)));
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.extra_data.len);
        try self.base_fee_per_gas.sszAppend(writer);
        try self.block_hash.sszAppend(writer);
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.transactions_bytes.len);
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.withdrawals_bytes.len);
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u64, self.blob_gas_used)));
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u64, self.excess_blob_gas)));

        // Dynamic section
        try writer.writeAll(self.extra_data);
        try writer.writeAll(self.transactions_bytes);
        try writer.writeAll(self.withdrawals_bytes);
    }

    pub fn toSszBytes(self: *const Self, allocator: std.mem.Allocator) ![]u8 {
        var buf = std.ArrayList(u8).init(allocator);
        errdefer buf.deinit();
        try self.sszAppend(buf.writer());
        return buf.toOwnedSlice();
    }

    pub fn fromSszBytes(bytes: []const u8) !Self {
        if (bytes.len < 528) return error.BufferTooSmall;
        const offset0 = std.mem.readInt(u32, bytes[436..440][0..4], .little);
        if (offset0 != 528) return error.InvalidOffset;
        const offset1 = std.mem.readInt(u32, bytes[504..508][0..4], .little);
        if (offset1 < offset0 or offset1 > bytes.len) return error.InvalidOffset;
        const offset2 = std.mem.readInt(u32, bytes[508..512][0..4], .little);
        if (offset2 < offset1 or offset2 > bytes.len) return error.InvalidOffset;
        var result: Self = undefined;
        result.parent_hash = try Bytes32.fromSszBytes(bytes[0..32]);
        result.fee_recipient = try Bytes20.fromSszBytes(bytes[32..52]);
        result.state_root = try Bytes32.fromSszBytes(bytes[52..84]);
        result.receipts_root = try Bytes32.fromSszBytes(bytes[84..116]);
        result.logs_bloom = try Bytes256.fromSszBytes(bytes[116..372]);
        result.prev_randao = try Bytes32.fromSszBytes(bytes[372..404]);
        result.block_number = std.mem.readInt(u64, bytes[404..412][0..8], .little);
        result.gas_limit = std.mem.readInt(u64, bytes[412..420][0..8], .little);
        result.gas_used = std.mem.readInt(u64, bytes[420..428][0..8], .little);
        result.timestamp = std.mem.readInt(u64, bytes[428..436][0..8], .little);
        result.base_fee_per_gas = try Bytes32.fromSszBytes(bytes[440..472]);
        result.block_hash = try Bytes32.fromSszBytes(bytes[472..504]);
        result.blob_gas_used = std.mem.readInt(u64, bytes[512..520][0..8], .little);
        result.excess_blob_gas = std.mem.readInt(u64, bytes[520..528][0..8], .little);
        result.extra_data = bytes[offset0..offset1];
        result.transactions_bytes = bytes[offset1..offset2];
        result.withdrawals_bytes = bytes[offset2..bytes.len];
        return result;
    }

    pub fn treeHashRoot(self: *const Self) [32]u8 {
        var h = Hasher.init();
        self.treeHashWith(&h);
        return h.finish();
    }

    pub fn treeHashWith(self: *const Self, h: *Hasher) void {
        const idx = h.index();
        self.parent_hash.treeHashWith(h);
        self.fee_recipient.treeHashWith(h);
        self.state_root.treeHashWith(h);
        self.receipts_root.treeHashWith(h);
        self.logs_bloom.treeHashWith(h);
        self.prev_randao.treeHashWith(h);
        h.putUint64(self.block_number);
        h.putUint64(self.gas_limit);
        h.putUint64(self.gas_used);
        h.putUint64(self.timestamp);
        {
            const sub_idx = h.index();
            h.appendBytes32(self.extra_data);
            h.merkleizeWithMixin(sub_idx, self.extra_data.len, 1);
        }
        self.base_fee_per_gas.treeHashWith(h);
        self.block_hash.treeHashWith(h);
        {
            // transactions: List[ByteList] - parse offset table from raw bytes
            const sub_idx = h.index();
            const tx_bytes = self.transactions_bytes;
            if (tx_bytes.len >= 4) {
                const first_offset = std.mem.readInt(u32, tx_bytes[0..4], .little);
                const num_txs = first_offset / 4;
                var ti: usize = 0;
                while (ti < num_txs) : (ti += 1) {
                    const tx_start = std.mem.readInt(u32, tx_bytes[ti * 4 ..][0..4], .little);
                    const tx_end = if (ti + 1 < num_txs) std.mem.readInt(u32, tx_bytes[(ti + 1) * 4 ..][0..4], .little) else @as(u32, @intCast(tx_bytes.len));
                    const tx_data = tx_bytes[tx_start..tx_end];
                    const inner = h.index();
                    h.appendBytes32(tx_data);
                    h.merkleizeWithMixin(inner, tx_data.len, 33554432);
                }
                h.merkleizeWithMixin(sub_idx, num_txs, 1048576);
            } else {
                h.merkleizeWithMixin(sub_idx, 0, 1048576);
            }
        }
        {
            // withdrawals: List[Withdrawal] - fixed 44 bytes each
            const sub_idx = h.index();
            const num_withdrawals = self.withdrawals_bytes.len / 44;
            var wi: usize = 0;
            while (wi < num_withdrawals) : (wi += 1) {
                const w = Withdrawal.fromSszBytes(self.withdrawals_bytes[wi * 44 .. (wi + 1) * 44]) catch unreachable;
                w.treeHashWith(h);
            }
            h.merkleizeWithMixin(sub_idx, num_withdrawals, 16);
        }
        h.putUint64(self.blob_gas_used);
        h.putUint64(self.excess_blob_gas);
        h.merkleize(idx);
    }
};


pub const BeaconBlockBody = struct {
    randao_reveal: Bytes96,
    eth1_data: ETH1Data,
    graffiti: Bytes32,
    proposer_slashings: []ProposerSlashing,
    attester_slashings: []AttesterSlashing,
    attestations: []Attestation,
    deposits: []Deposit,
    voluntary_exits: []SignedVoluntaryExit,
    sync_aggregate: SyncAggregate,
    execution_payload: ExecutionPayload,
    bls_to_execution_changes: []SignedBLSToExecutionChange,
    blob_kzg_commitments: []KZGCommitment,

    const Self = @This();

    pub fn sszBytesLen(self: *const Self) usize {
        var size: usize = 392;
        size += self.proposer_slashings.len * 416;
        size += self.attester_slashings.len * 4;
        for (self.attester_slashings) |*item| {
            size += item.sszBytesLen();
        }
        size += self.attestations.len * 4;
        for (self.attestations) |*item| {
            size += item.sszBytesLen();
        }
        size += self.deposits.len * 1240;
        size += self.voluntary_exits.len * 112;
        size += self.execution_payload.sszBytesLen();
        size += self.bls_to_execution_changes.len * 172;
        size += self.blob_kzg_commitments.len * 48;
        return size;
    }

    pub fn sszAppend(self: *const Self, writer: anytype) !void {
        // Static section
        var offset: u32 = 392;
        try self.randao_reveal.sszAppend(writer);
        try self.eth1_data.sszAppend(writer);
        try self.graffiti.sszAppend(writer);
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.proposer_slashings.len * 416);
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.attester_slashings.len * 4);
        for (self.attester_slashings) |*item| {
            offset += @intCast(item.sszBytesLen());
        }
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.attestations.len * 4);
        for (self.attestations) |*item| {
            offset += @intCast(item.sszBytesLen());
        }
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.deposits.len * 1240);
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.voluntary_exits.len * 112);
        try self.sync_aggregate.sszAppend(writer);
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.execution_payload.sszBytesLen());
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.bls_to_execution_changes.len * 172);
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.blob_kzg_commitments.len * 48);

        // Dynamic section
        for (self.proposer_slashings) |*item| {
            try item.sszAppend(writer);
        }
        {
            var inner_offset: u32 = @intCast(self.attester_slashings.len * 4);
            for (self.attester_slashings) |*item| {
                try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, inner_offset)));
                inner_offset += @intCast(item.sszBytesLen());
            }
            for (self.attester_slashings) |*item| {
                try item.sszAppend(writer);
            }
        }
        {
            var inner_offset: u32 = @intCast(self.attestations.len * 4);
            for (self.attestations) |*item| {
                try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, inner_offset)));
                inner_offset += @intCast(item.sszBytesLen());
            }
            for (self.attestations) |*item| {
                try item.sszAppend(writer);
            }
        }
        for (self.deposits) |*item| {
            try item.sszAppend(writer);
        }
        for (self.voluntary_exits) |*item| {
            try item.sszAppend(writer);
        }
        try self.execution_payload.sszAppend(writer);
        for (self.bls_to_execution_changes) |*item| {
            try item.sszAppend(writer);
        }
        for (self.blob_kzg_commitments) |*item| {
            try item.sszAppend(writer);
        }
    }

    pub fn toSszBytes(self: *const Self, allocator: std.mem.Allocator) ![]u8 {
        var buf = std.ArrayList(u8).init(allocator);
        errdefer buf.deinit();
        try self.sszAppend(buf.writer());
        return buf.toOwnedSlice();
    }

    pub fn fromSszBytes(bytes: []const u8) !Self {
        if (bytes.len < 392) return error.BufferTooSmall;
        const offset0 = std.mem.readInt(u32, bytes[200..204][0..4], .little);
        if (offset0 != 392) return error.InvalidOffset;
        const offset1 = std.mem.readInt(u32, bytes[204..208][0..4], .little);
        if (offset1 < offset0 or offset1 > bytes.len) return error.InvalidOffset;
        const offset2 = std.mem.readInt(u32, bytes[208..212][0..4], .little);
        if (offset2 < offset1 or offset2 > bytes.len) return error.InvalidOffset;
        const offset3 = std.mem.readInt(u32, bytes[212..216][0..4], .little);
        if (offset3 < offset2 or offset3 > bytes.len) return error.InvalidOffset;
        const offset4 = std.mem.readInt(u32, bytes[216..220][0..4], .little);
        if (offset4 < offset3 or offset4 > bytes.len) return error.InvalidOffset;
        const offset5 = std.mem.readInt(u32, bytes[380..384][0..4], .little);
        if (offset5 < offset4 or offset5 > bytes.len) return error.InvalidOffset;
        const offset6 = std.mem.readInt(u32, bytes[384..388][0..4], .little);
        if (offset6 < offset5 or offset6 > bytes.len) return error.InvalidOffset;
        const offset7 = std.mem.readInt(u32, bytes[388..392][0..4], .little);
        if (offset7 < offset6 or offset7 > bytes.len) return error.InvalidOffset;
        var result: Self = undefined;
        result.randao_reveal = try Bytes96.fromSszBytes(bytes[0..96]);
        result.eth1_data = try ETH1Data.fromSszBytes(bytes[96..168]);
        result.graffiti = try Bytes32.fromSszBytes(bytes[168..200]);
        result.sync_aggregate = try SyncAggregate.fromSszBytes(bytes[220..380]);
        result.proposer_slashings = @constCast(bytes[offset0..offset1]);
        result.attester_slashings = @constCast(bytes[offset1..offset2]);
        result.attestations = @constCast(bytes[offset2..offset3]);
        result.deposits = @constCast(bytes[offset3..offset4]);
        result.voluntary_exits = @constCast(bytes[offset4..offset5]);
        result.execution_payload = try ExecutionPayload.fromSszBytes(bytes[offset5..offset6]);
        result.bls_to_execution_changes = @constCast(bytes[offset6..offset7]);
        result.blob_kzg_commitments = @constCast(bytes[offset7..bytes.len]);
        return result;
    }

    pub fn treeHashRoot(self: *const Self) [32]u8 {
        var h = Hasher.init();
        self.treeHashWith(&h);
        return h.finish();
    }

    pub fn treeHashWith(self: *const Self, h: *Hasher) void {
        const idx = h.index();
        self.randao_reveal.treeHashWith(h);
        self.eth1_data.treeHashWith(h);
        self.graffiti.treeHashWith(h);
        {
            const sub_idx = h.index();
            for (self.proposer_slashings) |*item| {
                item.treeHashWith(h);
            }
            h.merkleizeWithMixin(sub_idx, self.proposer_slashings.len, 16);
        }
        {
            const sub_idx = h.index();
            for (self.attester_slashings) |*item| {
                item.treeHashWith(h);
            }
            h.merkleizeWithMixin(sub_idx, self.attester_slashings.len, 2);
        }
        {
            const sub_idx = h.index();
            for (self.attestations) |*item| {
                item.treeHashWith(h);
            }
            h.merkleizeWithMixin(sub_idx, self.attestations.len, 128);
        }
        {
            const sub_idx = h.index();
            for (self.deposits) |*item| {
                item.treeHashWith(h);
            }
            h.merkleizeWithMixin(sub_idx, self.deposits.len, 16);
        }
        {
            const sub_idx = h.index();
            for (self.voluntary_exits) |*item| {
                item.treeHashWith(h);
            }
            h.merkleizeWithMixin(sub_idx, self.voluntary_exits.len, 16);
        }
        self.sync_aggregate.treeHashWith(h);
        self.execution_payload.treeHashWith(h);
        {
            const sub_idx = h.index();
            for (self.bls_to_execution_changes) |*item| {
                item.treeHashWith(h);
            }
            h.merkleizeWithMixin(sub_idx, self.bls_to_execution_changes.len, 16);
        }
        {
            const sub_idx = h.index();
            for (self.blob_kzg_commitments) |*item| {
                item.treeHashWith(h);
            }
            h.merkleizeWithMixin(sub_idx, self.blob_kzg_commitments.len, 4096);
        }
        h.merkleize(idx);
    }
};


pub const BeaconBlock = struct {
    slot: u64,
    proposer_index: u64,
    parent_root: Bytes32,
    state_root: Bytes32,
    body: BeaconBlockBody,

    const Self = @This();

    pub fn sszBytesLen(self: *const Self) usize {
        var size: usize = 84;
        size += self.body.sszBytesLen();
        return size;
    }

    pub fn sszAppend(self: *const Self, writer: anytype) !void {
        // Static section
        var offset: u32 = 84;
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u64, self.slot)));
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u64, self.proposer_index)));
        try self.parent_root.sszAppend(writer);
        try self.state_root.sszAppend(writer);
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.body.sszBytesLen());

        // Dynamic section
        try self.body.sszAppend(writer);
    }

    pub fn toSszBytes(self: *const Self, allocator: std.mem.Allocator) ![]u8 {
        var buf = std.ArrayList(u8).init(allocator);
        errdefer buf.deinit();
        try self.sszAppend(buf.writer());
        return buf.toOwnedSlice();
    }

    pub fn fromSszBytes(bytes: []const u8) !Self {
        if (bytes.len < 84) return error.BufferTooSmall;
        const offset0 = std.mem.readInt(u32, bytes[80..84][0..4], .little);
        if (offset0 != 84) return error.InvalidOffset;
        var result: Self = undefined;
        result.slot = std.mem.readInt(u64, bytes[0..8][0..8], .little);
        result.proposer_index = std.mem.readInt(u64, bytes[8..16][0..8], .little);
        result.parent_root = try Bytes32.fromSszBytes(bytes[16..48]);
        result.state_root = try Bytes32.fromSszBytes(bytes[48..80]);
        result.body = try BeaconBlockBody.fromSszBytes(bytes[offset0..bytes.len]);
        return result;
    }

    pub fn treeHashRoot(self: *const Self) [32]u8 {
        var h = Hasher.init();
        self.treeHashWith(&h);
        return h.finish();
    }

    pub fn treeHashWith(self: *const Self, h: *Hasher) void {
        const idx = h.index();
        h.putUint64(self.slot);
        h.putUint64(self.proposer_index);
        self.parent_root.treeHashWith(h);
        self.state_root.treeHashWith(h);
        self.body.treeHashWith(h);
        h.merkleize(idx);
    }
};


pub const SignedBeaconBlock = struct {
    message: BeaconBlock,
    signature: Bytes96,

    const Self = @This();

    pub fn sszBytesLen(self: *const Self) usize {
        var size: usize = 100;
        size += self.message.sszBytesLen();
        return size;
    }

    pub fn sszAppend(self: *const Self, writer: anytype) !void {
        // Static section
        var offset: u32 = 100;
        try writer.writeAll(std.mem.asBytes(&std.mem.nativeToLittle(u32, offset)));
        offset += @intCast(self.message.sszBytesLen());
        try self.signature.sszAppend(writer);

        // Dynamic section
        try self.message.sszAppend(writer);
    }

    pub fn toSszBytes(self: *const Self, allocator: std.mem.Allocator) ![]u8 {
        var buf = std.ArrayList(u8).init(allocator);
        errdefer buf.deinit();
        try self.sszAppend(buf.writer());
        return buf.toOwnedSlice();
    }

    pub fn fromSszBytes(bytes: []const u8) !Self {
        if (bytes.len < 100) return error.BufferTooSmall;
        const offset0 = std.mem.readInt(u32, bytes[0..4][0..4], .little);
        if (offset0 != 100) return error.InvalidOffset;
        var result: Self = undefined;
        result.signature = try Bytes96.fromSszBytes(bytes[4..100]);
        result.message = try BeaconBlock.fromSszBytes(bytes[offset0..bytes.len]);
        return result;
    }

    pub fn treeHashRoot(self: *const Self) [32]u8 {
        var h = Hasher.init();
        self.treeHashWith(&h);
        return h.finish();
    }

    pub fn treeHashWith(self: *const Self, h: *Hasher) void {
        const idx = h.index();
        self.message.treeHashWith(h);
        self.signature.treeHashWith(h);
        h.merkleize(idx);
    }
};


